#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Pause re-enrichment so the queue stops growing and enrichment can DRAIN the real backlog
(exit-0-safe, fully reversible). Stops reenrich/requeue timers; records queue + coverage
baseline so we can measure whether pending drops and coverage climbs."""
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=15):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='10s'; "+q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
out={"kind":"pause_reenrich","ts":int(time.time())}
try:
    units=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'").split()
    tgt=[u for u in units if ('reenrich' in u.lower() or 'requeue' in u.lower()) and u.endswith('.timer')]
    out["timers_targeted"]=tgt
    done=[]
    for u in tgt:
        done.append(u+":"+sh("systemctl stop %s 2>&1; systemctl disable %s 2>&1 | tail -1; echo paused"%(u,u)))
    out["paused"]=done
    # baseline (reversible: re-enable timers anytime)
    out["queue_pending"]=psql("SELECT count(*) FILTER (WHERE status='pending') FROM atlas.enrich_queue")
    out["queue_claimed"]=psql("SELECT count(*) FILTER (WHERE status='claimed') FROM atlas.enrich_queue")
    out["pg_conns"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["timers_remaining"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'reenrich|requeue|enrich' | awk '{print $5,$NF}'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/pause-reenrich.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"pause_reenrich","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
